// Context Point 5 — Collection Name (weight 5, raw max 8 normalized)
// ============================================================================
function scoreCollectionName(collections) {
    if (collections.length === 0)
        return buildPoint('collection-name', 'Collection Name', 'variables', 5, 0, 8, ['No collections found']);
    const bd = [];
    let raw = 0;
    const names = collections.map(c => c.name);
    // No default names
    const defaultPattern = /^(Variable )?Collection\s?\d*$/i;
    const hasDefaults = names.some(n => defaultPattern.test(n.trim()));
    if (!hasDefaults) {
        raw += 2;
        bd.push('+2 No default collection names');
    }
    else
        bd.push('+0 Default collection name(s) found ("Collection", "Collection 1", etc.)');
    // No duplicate names
    const unique = new Set(names.map(n => n.trim().toLowerCase()));
    if (unique.size === names.length) {
        raw += 2;
        bd.push('+2 No duplicate collection names');
    }
    else
        bd.push(`+0 ${names.length - unique.size} duplicate collection name(s)`);
    // No emoji
    const withEmoji = names.filter(n => hasEmoji(n));
    if (withEmoji.length === 0) {
        raw += 1;
        bd.push('+1 No emoji in collection names');
    }
    else
        bd.push(`+0 ${withEmoji.length} collection(s) have emoji`);
    // Consistent convention
    const casing = detectCasing(names);
    // Also check for dot-prefix consistency
    const dotPrefixed = names.filter(n => n.startsWith('.'));
    const hasDotConsistency = dotPrefixed.length === 0 || dotPrefixed.length === names.length;
    if (casing !== 'mixed' || hasDotConsistency) {
        raw += 2;
        bd.push('+2 Consistent naming convention');
    }
    else
        bd.push('+0 Inconsistent naming convention');
    // No whitespace
    const withWhitespace = names.filter(n => /^\s|\s$/.test(n));
    if (withWhitespace.length === 0) {
        raw += 1;
        bd.push('+1 No leading/trailing whitespace');
    }
    else
        bd.push(`+0 ${withWhitespace.length} collection(s) have leading/trailing whitespace`);
    // Raw max is 8, weight is 5 → normalization handles this
    return buildPoint('collection-name', 'Collection Name', 'variables', 5, raw, 8, bd);
}
