// Context Point 6 — Mode Names (weight 10)
// ============================================================================
function scoreModeNames(collections) {
    const allModes = collections.flatMap(c => c.modes.map(m => m.name));
    if (allModes.length === 0)
        return buildPoint('mode-names', 'Mode Names', 'variables', 10, 0, 10, ['No modes found']);
    const bd = [];
    let raw = 0;
    // No emoji
    const withEmoji = allModes.filter(n => hasEmoji(n));
    if (withEmoji.length === 0) {
        raw += 3;
        bd.push('+3 No emoji in any mode name');
    }
    else
        bd.push(`+0 ${withEmoji.length} mode(s) contain emoji`);
    // No "Mode 1" default
    const defaultPattern = /^Mode\s*\d+$/i;
    const hasDefaults = allModes.some(n => defaultPattern.test(n.trim()));
    if (!hasDefaults) {
        raw += 2;
        bd.push('+2 No default mode names ("Mode 1")');
    }
    else
        bd.push('+0 Default mode name(s) found');
    // Semantic names — describe dimension (light/dark, size, device, etc.)
    const semanticPatterns = /\b(light|dark|theme|mobile|tablet|desktop|small|medium|large|default|brand|compact|dense|regular|rtl|ltr|high.contrast|inverted|day|night|individual|premium|corporate)\b/i;
    const semanticModes = allModes.filter(n => semanticPatterns.test(n));
    if (pct(semanticModes.length, allModes.length) >= 0.5) {
        raw += 3;
        bd.push(`+3 ≥50% of mode names are semantically descriptive`);
    }
    else if (pct(semanticModes.length, allModes.length) >= 0.25) {
        raw += 1;
        bd.push(`+1 Some mode names are semantically descriptive`);
    }
    else
        bd.push('+0 Mode names lack semantic clarity');
    // Consistent convention
    const casing = detectCasing(allModes);
    if (casing !== 'mixed') {
        raw += 2;
        bd.push(`+2 Consistent naming convention (${casing})`);
    }
    else
        bd.push('+0 Inconsistent naming convention across modes');
    return buildPoint('mode-names', 'Mode Names', 'variables', 10, raw, 10, bd);
}
